#include<bits/stdc++.h>
using namespace std;
vector<pair<int,int>> mp[1001];
int n,p,k;
int dis[1001];
bool vis[1001];
bool check(int x)
{
    queue<int> q;
    memset(dis,0x3f,sizeof(dis));
    dis[1]=0;
    q.push(1);
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        vis[t]=0;
        for(pair<int,int> i:mp[t])
        {
            int v=i.first,val=i.second;
            int temp=dis[t]+(val>x);
            if(dis[v]>temp)
            {
                dis[v]=temp;
                if(!vis[v])
                {
                    vis[v]=1;
                    q.push(v);
                }
            }
        }
    }
    return dis[n]<=k;
}
int main()
{
    
    scanf("%d%d%d",&n,&p,&k);
    for(int i=1;i<=p;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    int l=1,r=1e6,best=-1;
    while(l<=r)
    {
        int mid=(l+r)/2;
        if(check(mid))
        {
            r=mid-1;
            best=mid;
        }
        else
        {
            l=mid+1;
        }
    }
    printf("%d",best);
    return 0;
}
